{
  "grammar": [
    {
      "pattern": "對了 / 說到 + topic + 你覺得怎麼樣？",
      "structure": ["discourse marker", "topic", "question"],
      "explanation_en": "Use '對了' (by the way) or '說到...' (speaking of...) to smoothly shift to a new topic during a conversation.",
      "title": "Topic Shift Markers",
      "meaning": "Smoothly change the subject",
      "when_to_use": ["when you want to introduce a new but related topic", "when you remember something mid-conversation"],
      "when_not_to_use": ["when the current topic is not yet finished", "in very formal speeches"],
      "pragmatic_notes": "In Taiwan, '對了' is very common in casual chats; it signals a friendly, spontaneous shift. '說到...' is slightly more formal but still natural.",
      "word_order_notes": "Place the marker at the beginning of your sentence, followed by the new topic and then your question or comment.",
      "english_contrast": "English uses 'by the way' or 'speaking of which' similarly, but Chinese markers are more frequent and less abrupt.",
      "korean_contrast": "Korean uses '그런데' or '근데' for topic shifts, similar in function but placed at the start of a sentence.",
      "negative_examples": [
        {
          "text": "你覺得怎麼樣對了？",
          "error": "The topic shift marker should come first, not at the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "對了，你覺得怎麼樣？",
          "error": "Missing the topic after the marker; the listener won't know what you're referring to."
        }
      ],
      "transformation_drills": ["Change '對了，你喜歡看電影嗎？' to '說到電影，你喜歡看什麼？'"],
      "production_drills": ["Use '對了' to ask a friend about their weekend plans after talking about work."],
      "common_error_patterns": ["Forgetting to state the new topic after the marker", "Using the marker in the middle of a sentence"],
      "repair_feedback": {
        "word_order": "Put the marker at the very beginning.",
        "politeness": "It's fine in casual settings; avoid in very formal contexts.",
        "vocabulary": "Use '對了' for casual, '說到' for slightly more formal."
      }
    },
    {
      "pattern": "Noun + 呢？",
      "structure": ["noun", "呢"],
      "explanation_en": "Use '呢' after a noun to mean 'and what about...?' or 'how about...?', inviting the listener to share their own information.",
      "title": "呢 for Reciprocal Questions",
      "meaning": "And what about you?",
      "when_to_use": ["after someone has shared something about themselves", "to ask for the other person's opinion or situation"],
      "when_not_to_use": ["when you haven't established a context", "in yes/no questions (use 嗎 instead)"],
      "pragmatic_notes": "Very common in Taiwanese Mandarin to keep conversation flowing. It shows you're interested in the other person.",
      "word_order_notes": "Place '呢' directly after the noun or noun phrase, no verb needed.",
      "english_contrast": "English requires a full question like 'What about you?'; Chinese is more concise.",
      "korean_contrast": "Korean uses '~은/는요?' similarly, placed after the topic.",
      "negative_examples": [
        {
          "text": "你呢？",
          "error": "This is actually correct! But if you say '你嗎？' it becomes a yes/no question, not reciprocal."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你喜歡嗎？",
          "error": "This is a yes/no question, not a reciprocal 'what about you' question."
        }
      ],
      "transformation_drills": ["Change '我喜歡看電影。你喜歡看電影嗎？' to '我喜歡看電影。你呢？'"],
      "production_drills": ["After saying your hobby, use '呢' to ask your partner about theirs."],
      "common_error_patterns": ["Using '嗎' instead of '呢' for reciprocal questions", "Adding extra verbs after '呢'"],
      "repair_feedback": {
        "word_order": "Just noun + 呢, no verb needed.",
        "politeness": "Very polite and natural in all casual conversations.",
        "vocabulary": "Use with any noun: 你, 他, 你的工作, etc."
      }
    },
    {
      "pattern": "順便問一下，question",
      "structure": ["順便問一下", "question"],
      "explanation_en": "Use '順便問一下' (by the way, let me ask) to insert a related but secondary question naturally into the conversation.",
      "title": "順便問一下 for Incidental Questions",
      "meaning": "By the way, I'd like to ask...",
      "when_to_use": ["when you want to ask something related to the current topic but not the main point", "to avoid sounding too abrupt"],
      "when_not_to_use": ["for very important or urgent questions", "when you need a direct answer immediately"],
      "pragmatic_notes": "In Taiwan, this softens the question and makes it feel casual and friendly. It's a polite way to ask for extra information.",
      "word_order_notes": "Place '順便問一下' at the beginning of the question, followed by the full question.",
      "english_contrast": "Similar to 'by the way, can I ask...' but more concise and commonly used.",
      "korean_contrast": "Korean uses '참, 그런데' or '아, 그리고' for similar incidental questions.",
      "negative_examples": [
        {
          "text": "順便問一下，你喜歡嗎？",
          "error": "This is correct! But if you omit '一下', it sounds less natural."
        }
      ],
      "incorrect_examples": [
        {
          "text": "問一下順便，你喜歡嗎？",
          "error": "The phrase '順便問一下' is fixed; you cannot reorder the words."
        }
      ],
      "transformation_drills": ["Change '我想問你一個問題。你喜歡喝茶嗎？' to '順便問一下，你喜歡喝茶嗎？'"],
      "production_drills": ["After talking about a restaurant, use '順便問一下' to ask if they accept credit cards."],
      "common_error_patterns": ["Splitting the phrase or reordering words", "Using it for the main topic question"],
      "repair_feedback": {
        "word_order": "Keep '順便問一下' as a fixed phrase at the start.",
        "politeness": "Very polite and natural in Taiwan.",
        "vocabulary": "Use with any question; it's a set expression."
      }
    }
  ]
}
